要通过socket获取IGMP报文，您可以按照以下步骤进行操作：

1. 创建一个原始套接字（raw socket）：
   ```c
   int sockfd = socket(AF_INET, SOCK_RAW, IPPROTO_IGMP);
   if (sockfd < 0) {
       perror("Failed to create socket");
       exit(EXIT_FAILURE);
   }
   ```

2. 设置套接字选项，使其可以接收所有传入的IGMP报文：
   ```c
   int yes = 1;
   if (setsockopt(sockfd, IPPROTO_IP, IP_HDRINCL, &yes, sizeof(yes)) < 0) {
       perror("Failed to set socket option");
       exit(EXIT_FAILURE);
   }
   ```

3. 接收IGMP报文：
   ```c
   struct sockaddr_in sender_addr;
   socklen_t sender_addr_len = sizeof(sender_addr);
   char buffer[65536];

   ssize_t num_bytes = recvfrom(sockfd, buffer, sizeof(buffer), 0,
                                (struct sockaddr *)&sender_addr, &sender_addr_len);
   if (num_bytes < 0) {
       perror("Failed to receive IGMP packet");
       exit(EXIT_FAILURE);
   }
   ```

4. 处理接收到的IGMP报文：
   ```c
   // 可以在这里对接收到的buffer进行解析和处理
   // 初始化一个指向IP包头的指针，然后使用该指针来访问和解析IGMP报文内容
   struct iphdr *iph = (struct iphdr *)buffer;
   struct igmphdr *igmph = (struct igmphdr *)(buffer + iph->ihl * 4);

   // 打印IGMP报文源IP地址和目的IP地址
   printf("Source IP: %s\n", inet_ntoa((struct in_addr){iph->saddr}));
   printf("Dest IP: %s\n", inet_ntoa((struct in_addr){iph->daddr}));

   // 进一步根据实际情况进行报文内容的处理
   ```

注意：使用原始套接字需要具备root权限或CAP_NET_RAW能力。此外，要接收到IGMP报文，必须在进程所在的网络中加入相应的多播组或组所在的网络设备上启用混杂模式（promiscuous mode）。

以下是使用C语言通过socket接收IGMP报文的示例代码：

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <netinet/ip.h>
#include <netinet/igmp.h>

int main() {
    int sockfd;
    char buffer[65536];
    struct ip *iph;
    struct igmp *igmph;

    // 创建原始套接字
    sockfd = socket(AF_INET, SOCK_RAW, IPPROTO_IGMP);
    if (sockfd < 0) {
        perror("Failed to create socket");
        exit(EXIT_FAILURE);
    }

    // 无限循环接收IGMP报文
    while (1) {
        ssize_t num_bytes = recv(sockfd, buffer, sizeof(buffer), 0);
        if (num_bytes < 0) {
            perror("Failed to receive IGMP packet");
            exit(EXIT_FAILURE);
        }

        // 解析接收到的报文
        iph = (struct ip *)buffer;
        igmph = (struct igmp *)(buffer + iph->ip_hl * 4);

        // 打印IGMP报文信息
        printf("Source IP: %s\n", inet_ntoa(iph->ip_src));
        printf("Destination IP: %s\n", inet_ntoa(iph->ip_dst));
        printf("IGMP Type: %u\n", igmph->igmp_type);

        // 其他处理逻辑...

    }

    close(sockfd);
    return 0;
}
```

请注意，使用原始套接字需要root权限或CAP_NET_RAW能力。此外，要接收到IGMP报文，必须在进程所在网络中加入相应的多播组或组所在的网络设备上启用混杂模式（promiscuous mode）。
